// r1, r2: () — trivially equal.  This is one conjunct of det_*_equal.
assert(r1 == r2);

// For every `=~=` equality that the function's ensures gives us against
// `pre_self_`, lift the two-run pair to an equality between the two post
// states.  Each assertion is a pure tautology — `=~=` is set/map
// extensional equality, which Verus discharges automatically — so the
// asserts themselves verify from the proof fn's `requires` alone.
// Their effect is to give z3 ground facts of the shape
// `post1_self_.X == post2_self_.X` once the ensures premise fires.

// allocated_pages_4k/2m/1g (closed spec fn returns the ghost field; the
// ensures pins both runs down to `pre_self_`'s value).
assert(
    ((post1_self_.allocated_pages_4k() =~= pre_self_.allocated_pages_4k())
        && (post2_self_.allocated_pages_4k() =~= pre_self_.allocated_pages_4k()))
    ==> (post1_self_.allocated_pages_4k() == post2_self_.allocated_pages_4k())
);
assert(
    ((post1_self_.allocated_pages_2m() =~= pre_self_.allocated_pages_2m())
        && (post2_self_.allocated_pages_2m() =~= pre_self_.allocated_pages_2m()))
    ==> (post1_self_.allocated_pages_2m() == post2_self_.allocated_pages_2m())
);
assert(
    ((post1_self_.allocated_pages_1g() =~= pre_self_.allocated_pages_1g())
        && (post2_self_.allocated_pages_1g() =~= pre_self_.allocated_pages_1g()))
    ==> (post1_self_.allocated_pages_1g() == post2_self_.allocated_pages_1g())
);

// container_map_4k/2m/1g — the ensures gives `=~=` on the `@` views
// (i.e. the underlying `Map<ContainerPtr, Set<PagePtr>>`) directly.
assert(
    ((post1_self_.container_map_4k@ =~= pre_self_.container_map_4k@)
        && (post2_self_.container_map_4k@ =~= pre_self_.container_map_4k@))
    ==> (post1_self_.container_map_4k@ == post2_self_.container_map_4k@)
);
assert(
    ((post1_self_.container_map_2m@ =~= pre_self_.container_map_2m@)
        && (post2_self_.container_map_2m@ =~= pre_self_.container_map_2m@))
    ==> (post1_self_.container_map_2m@ == post2_self_.container_map_2m@)
);
assert(
    ((post1_self_.container_map_1g@ =~= pre_self_.container_map_1g@)
        && (post2_self_.container_map_1g@ =~= pre_self_.container_map_1g@))
    ==> (post1_self_.container_map_1g@ == post2_self_.container_map_1g@)
);

// free_pages_4k/2m/1g — only the lengths are pinned by ensures, so the
// strongest fact we can offer z3 is the equality of the two runs'
// lengths (with `pre_self_` as the bridge).  This is a tautology of
// arithmetic equality and is still useful as a trigger anchor.
assert(
    ((post1_self_.free_pages_4k().len() == pre_self_.free_pages_4k().len() - 512)
        && (post2_self_.free_pages_4k().len() == pre_self_.free_pages_4k().len() - 512))
    ==> (post1_self_.free_pages_4k().len() == post2_self_.free_pages_4k().len())
);
assert(
    ((post1_self_.free_pages_2m().len() == pre_self_.free_pages_2m().len() + 1)
        && (post2_self_.free_pages_2m().len() == pre_self_.free_pages_2m().len() + 1))
    ==> (post1_self_.free_pages_2m().len() == post2_self_.free_pages_2m().len())
);
assert(
    ((post1_self_.free_pages_1g().len() == pre_self_.free_pages_1g().len())
        && (post2_self_.free_pages_1g().len() == pre_self_.free_pages_1g().len()))
    ==> (post1_self_.free_pages_1g().len() == post2_self_.free_pages_1g().len())
);

// Quantifier alignment for the `forall|p: PagePtr|` ensures.  The two
// ensures clauses bind disjoint `post*_self_` instances; re-stating
// them as an implication forces z3 to instantiate both quantifiers and
// chain the mapping equalities via `pre_self_`.
assert(
    ((forall|p: PagePtr|
        post1_self_.page_is_mapped(p) ==>
            post1_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
            && post1_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p))
    && (forall|p: PagePtr|
        post2_self_.page_is_mapped(p) ==>
            post2_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
            && post2_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p)))
    ==>
    (forall|p: PagePtr|
        post1_self_.page_is_mapped(p) && post2_self_.page_is_mapped(p) ==>
            post1_self_.page_mappings(p) == post2_self_.page_mappings(p)
            && post1_self_.page_io_mappings(p) == post2_self_.page_io_mappings(p))
);
